create table dirkspzm32.isi_res_schicht (
    schicht_id                 number(*, 0) not null enable,
    parent_id                  number(*, 0) not null enable,
    sid                        varchar2(2 char) default '01' not null enable,
    firma_nr                   number(*, 0) default 1 not null enable,
    schicht_type               varchar2(1 char) default 'S' not null enable,
    schicht_name               varchar2(40 char) not null enable,
    start_date_time            date not null enable,
    ende_date_time             date not null enable,
    abzug_produktions_zeit_sek number(*, 0) default 0,
    prod_takt_id               number(*, 0),
    takt_zeit_sek              number(*, 0),
    created_date               date default sysdate not null enable,
    created_login_id           number(*, 0),
    last_change_date           date,
    last_change_login_id       number(*, 0),
    ist_takte_pro_schicht      number(*, 0) default 0 not null enable,
    ist_stk_pro_schicht        number(*, 0) default 0 not null enable,
    soll_takte_pro_schicht     number(*, 0) default 0 not null enable,
    soll_stk_pro_schicht       number(*, 0) default 0 not null enable,
    status                     varchar2(1 char) default 'N' not null enable,
    res_id                     number(*, 0),
    schicht_ende_variabel      varchar2(1 char) default 'F'
);

alter table dirkspzm32.isi_res_schicht
    add constraint chk_isi_res_schicht_status
        check ( status in ( 'N', 'U', 'B', 'F' ) ) enable;

alter table dirkspzm32.isi_res_schicht
    add constraint chk_isi_res_schicht_type
        check ( schicht_type in ( 'S', 'P' ) ) enable;

alter table dirkspzm32.isi_res_schicht
    add constraint pk_isi_res_schicht primary key ( schicht_id )
        using index enable;


